head.script:
/**
 * 반출입정보수정
 * id : op_301_01_20b
 */


scwin.pre_RowPosition = "";
scwin.autoPopYn = "";

scwin.onpageload = function() {
	// 세션정보
    let memJson = $c.data.getMemInfo();

    scwin.sUserId = $c.data.getMemInfo("userId");
    scwin.sUserClsCd = $c.data.getMemInfo("userClsCd");
    scwin.sClntNo = $c.data.getMemInfo("clntNo");
    scwin.sClntNm = $c.data.getMemInfo("clntNm");

    //물류상위점소코드 : loUpperLobranCd
    scwin.sLoUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd");

    scwin.params = $c.data.getParameter();

    scwin.lobranCd = $c.data.getParameter("lobranCd") || "";
    scwin.wrkPlCd = $c.data.getParameter("wrkPlCd") || "";
    scwin.cntrNo = $c.data.getParameter("cntrNo") || "";
    scwin.odrNo = $c.data.getParameter("odrNo") || "";

    if( scwin.lobranCd != "" ) {
        scwin.sLoUpperLobranCd = scwin.lobranCd;
    }

    const nowDate = new Date();
    const yyyy = nowDate.getFullYear();
    const mm = String(nowDate.getMonth() + 1).padStart(2, '0');
    const dd = String(nowDate.getDate()).padStart(2, '0');

    scwin.vCurDate = new Date().format("YYYYMMDD");

    const codeOptions = [
        { grpCd: "SD060", compID: "acb_lc_impExpClsCd" }, // 수입/수출
        { grpCd: "OP197", compID: "acb_lc_crryInOutCd,gr_gridView:crryinoutClsCd" }, // 반출/반입
        { grpCd: "OP171", compID: "acb_lc_fullEmptyClsCd,gr_gridView:fullEmptyClsCd" }, // F/E
        { grpCd: "OP101", compID: "acb_lc_siz" }, // SIZE
        { grpCd: "OP102", compID: "acb_lc_typ" }, // TYPE
        { grpCd: "SD113", compID: "acb_lc_odrKndCd" } // 오더종류
    ]
    $c.data.setCommonCode(codeOptions)

};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
	// udc_fromToCalendar UDC 에 있는 setInitDate 호출
    udc_calDt.setInitDate(scwin.vCurDate, scwin.vCurDate);
    //  udc_calDt.setInitDate("20250401", "20250401");
    //  ed_wrkPlCd.setValue("6C29");

    if( scwin.wrkPlCd != "" ) {
        //ed_wrkPlCd.setValue(scwin.wrkPlCd);
        txt_cntrNo.setValue(scwin.cntrNo);
        txt_odrNo.setValue(scwin.odrNo);
    }
    udc_pmc.setLabel("btn_cancel", "행취소");
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = async function (e) {

    // 작업장, 반출입일자
    let ret1 = await $c.gus.cfValidate([ed_wrkPlCd, ed_stDt, ed_endDt]);
    if ( !ret1 ) {
        return;
    }
    if (ed_stDt.getValue() > ed_endDt.getValue()) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ed_endDt.focus();
        return;
    }

    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        if( ds_outGrid.getRowCount() == 0 ) {
		    $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            totalRows.setValue("0");
        }
        ds_outGrid.sort("crryinoutClsCd", 0);
        gr_gridView.setColumnStyle("odrNo", "color", "blue");
        gr_gridView.setColumnStyle("odrNo", "text-decoration", "underline");
        totalRows.setValue(ds_outGrid.getRowCount());
        gr_gridView.setFocusedCell(0, 0);
        return false;
    }
};

//-------------------------------------------------------------------------
// 점소
//-------------------------------------------------------------------------
scwin.udc_wrkPl_onblurCodeEvent = function (e) {
    scwin.autoPopYn = "Y";
    udc_wrkPl.cfCommonPopUp(scwin.udc_wrkPl_callBackFunc,ed_wrkPlCd.getValue(),null,"T",null,null,null,null,null,null,null,null,null,null,"F","작업장,작업장코드,작업장명");
};

scwin.udc_wrkPl_onclickEvent = function (e) {
    scwin.autoPopYn = "N";
    udc_wrkPl.cfCommonPopUp(scwin.udc_wrkPl_callBackFunc,ed_wrkPlCd.getValue(),txt_wrkPlNm.getValue(),"F",null,null,null,null,null,null,null,null,null,null,"T","작업장,작업장코드,작업장명");
};

scwin.udc_wrkPl_callBackFunc = function (rtnList) {
    if( rtnList != null ) {
        ed_wrkPlCd.setValue(rtnList[0]); // 코드
        txt_wrkPlNm.setValue(rtnList[1]); // 명
        if("Y"==scwin.autoPopYn){//자동세팅 일 땐 
            scwin.lobranCd = rtnList[2]; // LOBRAN_CD
        }else{
            scwin.lobranCd = rtnList[4]; // LOBRAN_CD
        }
        scwin.autoPopYn = "";
    }

    dma_block.set("sysCd", "WorkPlaceEachGoodsEBC");
    dma_block.set("queryId", "retrivecBlockList");
    dma_block.set("param1", ed_wrkPlCd.getValue());
    $c.sbm.execute(sbm_block);
};

//-------------------------------------------------------------------------
// Line
//-------------------------------------------------------------------------
scwin.udc_line_onblurCodeEvent = function (e) {
    let pCode = ed_lineCd.getValue();
    let pName = txt_lineNm.getValue();
    let pClose = "T";
    let pAllSearch = "F";

    udc_line.cfCommonPopUp(scwin.udc_Line_callBackFunc,pCode,pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);
};

scwin.udc_line_onclickEvent =  function (e) {
    let pCode = ed_lineCd.getValue();
    let pName = txt_lineNm.getValue();
    let pClose = "F";
    let pAllSearch = "F";

    udc_line.cfCommonPopUp(scwin.udc_Line_callBackFunc,pCode,pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);
};

scwin.udc_Line_callBackFunc = function (rtnList) {
    if( rtnList != null ) { 
        ed_lineCd.setValue(rtnList[0]); // 코드
        txt_lineNm.setValue(rtnList[1]); // 명
    }
    else {
        ed_lineCd.setValue(""); // 코드
        txt_lineNm.setValue(""); // 명
    }
};

//-------------------------------------------------------------------------
// 선박
//-------------------------------------------------------------------------
scwin.udc_vssl_onblurCodeEvent = function (e) {
    let pCode = ed_vsslCd.getValue();
    let pName = txt_vsslNm.getValue();
    let pClose = "T";

    udc_vssl.cfCommonPopUp(scwin.udc_vssl_callBackFunc,pCode,pName,pClose,null,null,null,null,null,null,null,null,null,null,'F',null);
};

scwin.udc_vssl_onclickEvent = async function (e) {
    let pCode = ed_vsslCd.getValue();
    let pName = txt_vsslNm.getValue();
    let pClose = "F";

    udc_vssl.cfCommonPopUp(scwin.udc_vssl_callBackFunc,pCode,pName,pClose,null,null,null,null,null,null,null,null,null,null,'F',null);
};

scwin.udc_vssl_callBackFunc = function (rtnList) {
    if( rtnList != null ) { 
        ed_vsslCd.setValue(rtnList[0]); // 코드
        txt_vsslNm.setValue(rtnList[1]); // 명
    }
    else {
        ed_vsslCd.setValue(""); // 코드
        txt_vsslNm.setValue(""); // 명
    }
};

//-------------------------------------------------------------------------
// function name : f_vehclSearch
// function desc : 차량조회
//-------------------------------------------------------------------------
scwin.f_vehclSearch = function (param1, bCloseFlag,newv) {
    scwin.pre_RowPosition = ds_outGrid.getRowPosition();
    bCloseFlag = (bCloseFlag == null) ? 'T' : bCloseFlag;

    // let v_vehclShortCd = ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "vehclNo");
    let v_vehclShortCd = newv ?? ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "vehclNo");

    if( v_vehclShortCd.length >= 4 ) {
        v_vehclShortCd = v_vehclShortCd.substring(v_vehclShortCd.length-4, v_vehclShortCd.length);
    }

    var data = {
          paramTitle : "가용차량조회"
        , data : [ 
                [   // [0]번 인덱스 (첫 번째 그룹)
                    scwin.lobranCd,
                    "",
                    "",
                    "C",
                    scwin.vCurDate,
                    v_vehclShortCd,
                    "",
                    "",
                    "GATEINOUT",
                    "TR"
                ],
                [   // [1]번 인덱스 (두 번째 그룹)
                    "",
                    bCloseFlag
                ]
            ]
        , callbackFn : scwin.f_vehclSearch_callBackFunc
    };

    var opts = {
          id : "op_301_01_05p3"
        , popupName : "가용차량조회"
        , modal : true
        , type : "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title : "가용차량조회"  //Layer pop
        , width : 1220
        , height : 530
    };

    $c.win.openPopup("/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_05p3.xml", opts, data);
};

scwin.f_vehclSearch_callBackFunc = function (rtnList) {

    if( rtnList == null || (rtnList[0][0] == null && rtnList[0] == "N/A") ) {
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclNo", ""); // 코드
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclShortNo", ""); // 명
        return;
    }

    let firstList = new Array();
    for( var i = 0; i < rtnList.length; i++ ) {
        firstList = rtnList[0];

        //컨테이너는 트렉터만 배차 가능
        if( firstList[12] != "TR" ) {
            $c.gus.cfAlertMsg("컨테이너는 트렉터만 배차 가능합니다. \n\n트렉터 차량을 선택하세요.");
            ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclNo", "");
            ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclShortNo", "");
            return;
		}

        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "eqCd", firstList[0]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclNo", firstList[1]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclShortNo", firstList[2]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "bondTransStDt", firstList[3]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "bondTransEndDt", firstList[4]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "drvEmpNo", firstList[5]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "drvNm", firstList[6]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "drvTelNo", firstList[7]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "trsNo", firstList[8]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclIdCardNo", firstList[9]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "chassisEqCd", firstList[10]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "chassisNo", firstList[11]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclKndCd", firstList[12]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "vehclNrmCd", firstList[13]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "selfSpotClsCd", firstList[14]);
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "copCoClntNo", firstList[15]);

    }

    return false;
};

//-------------------------------------------------------------------------
// function name : f_chassisSearch
// function desc : 샤시조회
//-------------------------------------------------------------------------
scwin.f_chassisSearch = function (bCloseFlag, newv) {
    bCloseFlag = (bCloseFlag == null) ? 'T' : bCloseFlag;
    pClose = "F";
    let row = ds_outGrid.getRowPosition();
    let pCode = newv ?? ds_outGrid.getCellData(row, "chassisNo");

    if( pCode.length >= 4 ) {
        pCode = pCode.substring(pCode.length-4, pCode.length);
    }
    pName = "";
    let lobranCd = scwin.lobranCd;

    udc_gridComCode1.setSelectId('retrieveChassis2'); // XML상의 SELECT ID
    udc_gridComCode1.cfCommonPopUp(
        scwin.f_chassisSearch_callBackFunc
        , pCode					// 화면에서의 ??? Code Element의	getValue()
        , pName					// 화면에서의 ??? Name Element의	getValue()
        , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        , null					// Title순서	
        , null					// 보여주는 각 컬럼들의 폭	
        , null					// 컬럼중에서 숨기는	컬럼 지정	
        , 'TL,'+lobranCd					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
        , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
        , null					// 윈도우 위치 Y좌표	
        , null					// 윈도우 위치 X좌표
        , null					// 중복체크여부	('F')
        , 'T'					// 전체검색허용여부	('F')
        , '샤시조회,단축번호,샤시번호'				// POP-UP Window Title 검색어1,2	 ('Win타이틀,첫번검색Nm,두번?검색Nm')
    );


};

scwin.f_chassisSearch_callBackFunc = function (rtnList) {
    if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != 'N/A') {
        ds_outGrid.setCellData(scwin.pre_RowPosition, "chassisNo", rtnList[1]); // 코드
        ds_outGrid.setCellData(scwin.pre_RowPosition, "chassisEqCd", rtnList[4]); // 명

        dma_chassisNoChangeInfo.setEmptyValue();
        dma_chassisNoChangeInfo.set("eqCd", ds_outGrid.getCellData(scwin.pre_RowPosition, "eqCd"));
        dma_chassisNoChangeInfo.set("logisLnkEqCd", rtnList[4]);
        ds_chassisNoChangeResult.removeAll();
        $c.sbm.execute(sbm_chassisNoChangeInfo);
    }
};

scwin.sbm_chassisNoChangeInfo_submitdone = async function (e) {
    if( ds_chassisNoChangeResult.getCellData(0, "value") == "1" ) {
        let confirm = await $c.win.confirm("해당 샤시장비는 이미 다른 차량에 등록되어 있습니다.\n계속 진행 하시겠습니까?")
        if( confirm ) {

        }
        else {
            ds_outGrid.setCellData(scwin.pre_RowPosition, "chassisNo", scwin.pre_chassisNo);
            ds_outGrid.setCellData(scwin.pre_RowPosition, "chassisEqCd", scwin.pre_chassisEqCd);
        }
    }
};

//-------------------------------------------------------------------------
// function name : f_cntrSearch
// function desc : 컨테이너번호조회
//-------------------------------------------------------------------------
scwin.f_cntrSearch = function (bCloseFlag) {
    scwin.pre_RowPosition = ds_outGrid.getRowPosition();
    bCloseFlag = (bCloseFlag == null) ? 'T' : bCloseFlag;
    pClose = bCloseFlag;

    var pOdrNo = ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "odrNo");
    var pWrkPlCd = ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "wrkPlCd");
    var pCntrNo = ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "cntrNo");

    //공통코드 retrieveGateInOutCntrNo
};

scwin.f_cntrSearch_callBackFunc = function (rtnList) {
    if( rtnList == null ) {
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "cntrNo", scwin.pre_cntrNo);
        //gr_gridView.setCellStyle(rowIndex, "gridChkBox", styleName, styleValue);
        return;
    }
    else {
        let row = ds_outGrid.getRowPosition();
        ds_outGrid.setCellData(row, "cntrNo", rtnList[0]);

        dma_cntrNoChangeInfo.set("wrkPlCd", ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "wrkPlCd"));
        dma_cntrNoChangeInfo.set("crryinoutClsCd", ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "crryinoutClsCd"));
        dma_cntrNoChangeInfo.set("cntrNo", ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "cntrNo"));
        dma_cntrNoChangeInfo.set("odrNo", ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "odrNo"));
        dma_cntrNoChangeInfo.set("cntrSeq", ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "cntrSeq"));
        dma_cntrNoChangeInfo.set("cntrNoYn", ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "cntrNoYn"));
        dma_cntrNoChangeInfo.set("wrkPathSeq", ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "wrkPathSeq"));
        dma_cntrNoChangeInfo.set("wrkStpSeq", ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "wrkStpSeq"));

        $c.sbm.execute(sbm_cntrNoChangeInfo);
    }
};

scwin.sbm_cntrNoChangeInfo_submitdone = function (e) {

    let rowCnt = ds_cntrNoChangeResult.getRowCount();

    //컨테이너번호 수정인 경우
    if (ds_outGrid.getCellData(scwin.pre_RowPosition, "cntrNoYn") == "1") {
        if ( rowCnt == 0 || ds_cntrNoChangeResult.getCellData(0, 'odrCntrNoYn') == "0") { //컨테이너정보(TB_SD404) 또는 오더 컨테이너(TB_SD403)에 컨테이너 번호 미등록된 경우
            if( rowCnt == 0 ) {
                $c.gus.cfAlertMsg("컨테이너정보에 없는 컨테이너 번호입니다.\n컨테이너 번호를 확인하십시요.");
            }
	        else {
                $c.gus.cfAlertMsg("오더에 미등록된 컨테이너 번호입니다.\n컨테이너 번호를 확인하십시요.");
            }

	        ds_outGrid.setRowPosition(scwin.pre_RowPosition);
	        //gr_gridView.SetColumn('cntrNo');
	        ds_outGrid.setCellData(scwin.pre_RowPosition, 'cntrNo', scwin.pre_cntrNo);
	        gr_gridView.setFocusedCell(0, 0);
	        //gr_gridView.ColumnProp("cntrNo", "Edit") = "Upper";
	    } else if ( ds_cntrNoChangeResult.getCellData(0, 'crryinoutYn') > 0 ) {	//반출입이 발생한 경우
	        $c.gus.cfAlertMsg("이미 반입 또는 반출된  컨테이너 번호입니다.\n컨테이너 번호를 확인하십시요.");
	        ds_outGrid.setRowPosition(scwin.pre_RowPosition);
	        //gr_gridView.SetColumn('cntrNo');
	        ds_outGrid.setCellData(scwin.pre_RowPosition, 'cntrNo', scwin.pre_cntrNo);
	        gr_gridView.setFocusedCell(0, 0);
	       // gr_gridView.ColumnProp("cntrNo", "Edit") = "Upper";
	    } else if ( scwin.pre_cntrNo != ds_cntrNoChangeResult.getCellData(0, 'cntrNo') ) {
	    	if( ds_cntrNoChangeResult.getCellData(0, 'currPosCd') != ed_wrkPlCd.getValue() ) {	//컨테이너정보의 현위치와 반출작업장이 틀린경우
		        $c.gus.cfAlertMsg("현 작업장에 없는 컨테이너 번호 입니다..\n컨테이너 번호를 확인하십시요.");
		        ds_outGrid.setRowPosition(scwin.pre_RowPosition);
		        //gr_gridView.SetColumn('cntrNo');
		        ds_outGrid.setCellData(scwin.pre_RowPosition, 'cntrNo', scwin.pre_cntrNo);
		        gr_gridView.setFocusedCell(0, 0);
		        //gr_gridView.ColumnProp("cntrNo", "Edit") = "Upper";
		        return;
			}
    		if( ds_outGrid.getCellData(scwin.pre_RowPosition, 'cntrSizCd') != ds_cntrNoChangeResult.getCellData(0, 'cntrSizCd')
    		  || ds_outGrid.getCellData(scwin.pre_RowPosition, 'cntrTypCd') != ds_cntrNoChangeResult.getCellData(0, 'cntrTypCd') ) {
    			$c.gus.cfAlertMsg("컨테이너 SIZE, TYPE 이 일치하지 않습니다.\n컨테이너 번호를 확인하십시요.");
		        ds_outGrid.setRowPosition(scwin.pre_RowPosition);
		        //gr_gridView.SetColumn('cntrNo');
		        ds_outGrid.setCellData(scwin.pre_RowPosition, 'cntrNo', scwin.pre_cntrNo);
		        gr_gridView.setFocusedCell(0, 0);
		        //gr_gridView.ColumnProp("cntrNo", "Edit") = "Upper";
    			return;
    		}

			ds_outGrid.setCellData(scwin.pre_RowPosition, 'cntrNoChangeYn', "1");
			ds_outGrid.setCellData(scwin.pre_RowPosition, 'cntrNo', ds_cntrNoChangeResult.getCellData(0, 'cntrNo'));
			ds_outGrid.setCellData(scwin.pre_RowPosition, 'crryinGatelogNo', ds_cntrNoChangeResult.getCellData(0, 'crryinGatelogNo'));
			ds_outGrid.setCellData(scwin.pre_RowPosition, 'extdDueDt', ds_cntrNoChangeResult.getCellData(0, 'extdDueDt'));
			ds_outGrid.setCellData(scwin.pre_RowPosition, 'extdMgntNo', ds_cntrNoChangeResult.getCellData(0, 'extdMgntNo'));
			ds_outGrid.setCellData(scwin.pre_RowPosition, 'rettlClsCd', ds_cntrNoChangeResult.getCellData(0, 'rettlClsCd'));
			ds_outGrid.setCellData(scwin.pre_RowPosition, 'impExpClsCd', ds_cntrNoChangeResult.getCellData(0, 'impExpClsCd'));
