scwin.btn_ozprint_onclick = function (e) {

    var row = ds_outGrid.getRowPosition();
    var check = ds_outGrid.getCellData(row, "gridChkBox");

    var totRow = ds_outGrid.getRowCount();
    var crryinoutIntendNo = "";

    for( i = 0; i < totRow; i++ ) {
        check = ds_outGrid.getCellData(i, "gridChkBox");

        if( check == 1 ) {
            crryinoutIntendNo = crryinoutIntendNo +"TO_CHAR("+ds_outGrid.getCellData(i, "crryinoutIntendNo")+"),";
        }
    }

    crryinoutIntendNo = crryinoutIntendNo.substring( 0 , crryinoutIntendNo.length-1 ); 

    if( crryinoutIntendNo.length == 0 ) {
        $c.gus.cfAlertMsg("선택된 항목이 없습니다.");
        return;
    }

    // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
	var odiParam = new ODIParam("op_301_01_05r");
	odiParam.add("crryinoutIntendNo", crryinoutIntendNo );

    let reportFile = "/ds/op/wrkplan/transwrkplan/op_301_01_05r.ozr";
    let odiName = "op_301_01_05r";
    let data = {
        odiName: odiName,
        reportName: reportFile,
        odiParam: odiParam,
        viewerParam: {
            "useprogressbar": true, // 프로그레스바 쓸지 말지
            "mode": mode,
        },
        formParam: {
        }
    };

    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: false,
        type: "browserPopup",
        width: 1000,
        height: 830,
        title: "오즈 리포트"
    };

    $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

//-------------------------------------------------------------------------
// function name : f_crryInOutEDI
// function desc : 반출입예정정보EDI등록
//-------------------------------------------------------------------------
scwin.btn_carryingInOutEDI_onclick = function (e) {

    let row = ds_outGrid.getRowPosition();

    if( ds_outGrid.getRowCount() == 0 ) {
        $c.win.alert("조회 대상 없음");
        return;
    }

    if( ds_outGrid.getCellData(row, "vehclNo") == "" ){
        $c.gus.cfAlertMsg("운송차량이 없습니다");
        return false;
    }

    let dptWrkPlCd = "";
    let arvWrkPlCd = "";
    let dptWrkPlNm = "";
    let arvWrkPlNm = "";

    if( ds_outGrid.getCellData(row, "crryinoutClsCd") == "I" ) {
        dptWrkPlCd = ds_outGrid.getCellData(row, "dptArvWrkPlCd");
        arvWrkPlCd = ds_outGrid.getCellData(row, "wrkPlCd");
        dptWrkPlNm = ds_outGrid.getCellData(row, "wrkPlNm");
        arvWrkPlNm = txt_wrkPlNm.getValue();
    }
    else if( ds_outGrid.getCellData(row, "crryinoutClsCd") == "O" ) {
        dptWrkPlCd = ds_outGrid.getCellData(row, "wrkPlCd");
        arvWrkPlCd = ds_outGrid.getCellData(row, "dptArvWrkPlCd");
        dptWrkPlNm = txt_wrkPlNm.getValue();
        arvWrkPlNm = ds_outGrid.getCellData(row, "wrkPlNm");
    }

    var data = {
          crryoutEdiType : ds_outGrid.getCellData(row, "crryoutEdiType")
        , crryinEdiType : ds_outGrid.getCellData(row, "crryinEdiType")
        , arrParam : [
            [
                  "1"
                , ds_outGrid.getCellData(row, "transWrkIndictNo")
                , ds_outGrid.getCellData(row, "odrNo")
                , ds_outGrid.getCellData(row, "cntrSeq")
                , ds_outGrid.getCellData(row, "wrkPathSeq")
                , ds_outGrid.getCellData(row, "wrkStpSeq")
                , ds_outGrid.getCellData(row, "vehclShortCd")
                , ds_outGrid.getCellData(row, "vehclNo")
                , ds_outGrid.getCellData(row, "vehclIdCardNo")
                , ds_outGrid.getCellData(row, "wrkStDt")
                , ds_outGrid.getCellData(row, "wrkEndDt")
                , ds_outGrid.getCellData(row, "cntrNo")
                , dptWrkPlCd
                , arvWrkPlCd
                , dptWrkPlNm
                , arvWrkPlNm
                , ds_outGrid.getCellData(row, "crryoutEdiType")
                , ds_outGrid.getCellData(row, "crryinEdiType")
            ], [
                  ds_outGrid.getCellData(row, "transWrkIndictNo")
                , ds_outGrid.getCellData(row, "vehclNo")
                , ds_outGrid.getCellData(row, "vehclIdCardNo")
                , ds_outGrid.getCellData(row, "drvNm")
                , ds_outGrid.getCellData(row, "drvTelNo")
                , ds_outGrid.getCellData(row, "crryinoutDthh").substring(0,8)
                , ds_outGrid.getCellData(row, "crryinoutDthh").substring(8,12)
                , ds_outGrid.getCellData(row, "crryinoutDthh").substring(0,8)
                , ds_outGrid.getCellData(row, "crryinoutDthh").substring(8,12)
                , ds_outGrid.getCellData(row, "vehclShortNo")
                , ds_outGrid.getCellData(row, "eqCd")
            ]
        ]
        , callbackFn : scwin.carryingInOutEDI_callBackFunc
    };

    var opts = {
          id : "op_202_02_21p"
        , popupName : "반출입예정정보EDI등록"
        , modal : true
        , type : "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title : "반출입예정정보EDI등록"  //Layer pop
        , width : 1100
        , height : 850
    };

    $c.win.openPopup("/ui/ds/op/wrkplan/transwrkplan/op_202_02_21p.xml", opts, data);
};

