};

scwin.f_gridColumnData2 = function (Flag) {
    var Flag2 = ds_outGrid.getCellData(ds_outGrid.getRowPosition(), "crryoutEdiType");
    var str1 = $c.gus.decode(Flag, "", "미등록", "3", "미전송", "1", "전송완료", "0", "전송대기", "5", "필수항목오류", "");
    var str2 = $c.gus.decode(Flag2, "CO", "(COPINO)", "CD", "(COPI_CODECO)", "");
    var rtnStr = str1 + str2;
    return rtnStr; 
};

scwin.f_gridColumnData3 = function (Flag) {
