    return $c.gus.decode(Flag, "", "미등록", "3", "미전송", "1", "전송완료", "0", "전송대기", "5", "필수항목오류", "") + $c.gus.decode(Flag2, "CO", "(COPINO)", "CD", "(COPI_CODECO)", "");
};

scwin.f_customFormatter = function (data, formattedData, rowIndex, colIndex) {

    let columnId = gr_gridView.getColumnID(colIndex);
    let data2 = "";
    let rtnVal = "";

    if (columnId == "crryinEdiFlag1") {
        rtnVal = $c.gus.decode(data, "1","전송","3","전송대기","5","오류","");
    }
    else if (columnId == "crryoutEdiFlag") {
        data2 = ds_outGrid.getCellData(rowIndex, "crryoutEdiType");
        rtnVal = $c.gus.decode(data, "", "미등록", "3", "미전송", "1", "전송완료", "0", "전송대기", "5", "필수항목오류", "") + $c.gus.decode(data2, "CO", "(COPINO)", "CD", "(COPI_CODECO)", "");
    }
    else if (columnId == "crryinEdiFlag") {
        data2 = ds_outGrid.getCellData(rowIndex, "crryinEdiType");
        rtnVal = $c.gus.decode(data, "", "미등록", "3", "미전송", "1", "전송완료", "0", "전송대기", "5", "필수항목오류", "") + $c.gus.decode(data2, "CO", "(COPINO)", "CD", "(COPI_CODECO)", "");
    }

    return rtnVal;
}

scwin.gr_gridView_oncellclick = function (rowIndex, columnIndex, columnId) {
    if( columnId == "odrNo" ) {
        var data = {
            callbackFn : scwin.op_301_01_05p_callBackFunc
        };

        var opts = {
            id : "op_301_01_05p"
            , popupName : "반출입 예정 정보 상세 현황"
            , modal : true
            , type : "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
            , title : "반출입 예정 정보 상세 현황"  //Layer pop
            , width : 820
            , height : 200
        };

        $c.win.openPopup("/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_05p.xml", opts, data);
    }
    else if( columnId == "cntrSizCd" ) {
        //냉동컨테이너 온도 수정
        // if (ds_outGrid.getCellData(rowIndex, "cntrTypCd") != "RF") return;

        var data = {
            callbackFn : scwin.op_301_01_05p2_callBackFunc
        };

        var opts = {
            id : "op_301_01_05p2"
            , popupName : "냉동컨테이너등록"
            , modal : true
            , type : "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
            , title : "냉동컨테이너등록"  //Layer pop
            , width : 350
            , height : 250
        };

        //asis 팝업 주석 처리 되어 있지만 테스트 위해서 임시로 품
        // $c.win.openPopup("/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_05p2.xml", opts, data);
    }
    else if( columnId == "gridChkBox" ) {
        if( ds_outGrid.getCellData(rowIndex, "gridChkBox") == "1" ) {
            if( ds_outGrid.getCellData(rowIndex, "crryinoutIntendNo") == "" ) {
                $c.gus.cfAlertMsg("반출입 예정번호가 없습니다.\n취소 불가능 합니다.");
			    ds_outGrid.setCellData(rowIndex, "gridChkBox", 0);
		    	return;
            }
            if( ds_outGrid.getCellData(rowIndex, "cntrNo") == "" ) {
                $c.gus.cfAlertMsg("컨테이너번호가 없습니다.");
			    ds_outGrid.setCellData(rowIndex, "gridChkBox", 0);
		    	return;
            }
            if( ds_outGrid.getCellData(rowIndex, "vehclNo") == "" ) {
                $c.gus.cfAlertMsg("차량번호가 없습니다.");
			    ds_outGrid.setCellData(rowIndex, "gridChkBox", 0);
		    	return;
            }
            if( ds_outGrid.getCellData(rowIndex, "chassisNo") == "" 
             && ds_outGrid.getCellData(rowIndex, "selfSpotClsCd") != "1"
             && ds_outGrid.getCellData(rowIndex, "selfClsCd") != DsConstants.SELF_CLS_CD_SELF_CRRYOUT ) {
                $c.gus.cfAlertMsg("샤시 번호가 없습니다.");
			    ds_outGrid.setCellData(rowIndex, "gridChkBox", 0);
		    	return;
            }
            if( ds_outGrid.getCellData(rowIndex, "arrvlportDtm") == "" ) {
                $c.gus.cfAlertMsg("입항일시가 없습니다.");
			    ds_outGrid.setCellData(rowIndex, "gridChkBox", 0);
		    	return;
            }

            dma_managementItem.set("crryinoutDtFrom", ds_outGrid.getCellData(rowIndex, "crryinoutDthh"));
            dma_managementItem.set("arrvlportDtm", ds_outGrid.getCellData(rowIndex, "arrvlportDtm"));
            dma_managementItem.set("cntrNo", ds_outGrid.getCellData(rowIndex, "cntrNo"));
            $c.sbm.execute(sbm_managementItem);
        }
    }
};

scwin.sbm_managementItem_submitdone = function (e) {
    var blnGateProcessOk = true;

    if( ds_managementItem.getRowCount() == 0 ) {
        $c.gus.cfAlertMsg("제어항목 체크중 데이타오류");
        ds_outGrid.setCellData(ds_outGrid.getRowPosition(), "gridChkBox", 0);
